#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);
    auto recompute_count = reaction::var(0);

    auto calc = reaction::calc([a, b, &recompute_count]() {
        return a.get() + b.get();
    }, {a, b}, [&recompute_count](int result) {
        recompute_count.set(recompute_count.get() + 1);
    });

    // Non-batch updates
    a.set(nonBatchA);
    b.set(nonBatchB);
    int after_non_batch = recompute_count.get();

    // Batch updates
    auto batch = reaction::batch();
    a.set(batchA);
    b.set(batchB);
    batch.execute();
    int after_batch = recompute_count.get();

    return {calc.get(), after_non_batch, after_batch};
}

}  // namespace test_reaction

