        .finalValue = impl.value(),
        .addReportedChange = addChanged,
        .multiplyReportedChange = mulChanged,
        .andReportedChange = andChanged,
        .leftShiftReportedChange = shiftChanged,
        .incrementReportedChange = incChanged,
